sql:
SELECT plan_name
FROM house_plans
WHERE lot_size > 10000;

SELECT COUNT(customer_id) 
FROM customers 
WHERE referral_source IN (SELECT campaign_name FROM marketing_campaigns);

external_knowledge:
- "showed interest" refers to generating a lead;
- "ultimately bought something" indicates that the purchase was made;
- "during the past year" specifies the period from January 1, 2022, to December 31, 2022.

sql:
SELECT AVG(square_footage)
FROM house_plans
WHERE availability = 'available';

SELECT sales.sale_id, sales.total_price, sales.number_of_units, house_plans.plan_name, house_plans.square_footage
FROM sales
INNER JOIN house_plans ON sales.plan_id = house_plans.plan_id;

SELECT plan_id, number_of_bedrooms
FROM house_plans
WHERE plan_id = 1;

SELECT plan_name, garage_type
FROM house_plans
WHERE availability = 'available';
